#include <stdio.h>

int main() {
    int n, index;
    scanf("%d", &n);
    int arr[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &index);

    int *ptr = &arr[index];
    printf("%d\n", *ptr);
    ptr--;
    printf("%d\n", *ptr);

    return 0;
}
